#include <stdio.h>

char *sumset(int arr[], int size) {
    static char output[100000];
    int len_a;
    int len_b;
    int offset = 0;
    int sums[10000];
    int count = 0;

    if (size < 2) {
        output[0] = '\0';
        return output;
    }

    len_a = arr[0];
    if (1 + len_a >= size) {
        output[0] = '\0';
        return output;
    }
    len_b = arr[1 + len_a];
    if (2 + len_a + len_b > size) {
        output[0] = '\0';
        return output;
    }

    for (int j = 0; j < len_b; j++) {
        int b = arr[2 + len_a + j];
        for (int i = 0; i < len_a; i++) {
            int a = arr[1 + i];
            sums[count++] = a + b;
        }
    }

    for (int i = 0; i < count; i++) {
        for (int j = i + 1; j < count; j++) {
            if (sums[j] < sums[i]) {
                int temp = sums[i];
                sums[i] = sums[j];
                sums[j] = temp;
            }
        }
    }

    output[0] = '\0';
    for (int i = 0; i < count; i++) {
        offset += snprintf(
            output + offset,
            sizeof(output) - (size_t)offset,
            "%s%d",
            offset == 0 ? "" : " ",
            sums[i]
        );
    }

    return output;
}

#include <algorithm>
#include <vector>

std::vector<int> sumset(const std::vector<int>& set_a, const std::vector<int>& set_b) {
    std::vector<int> result;
    result.reserve(set_a.size() * set_b.size());

    for (int a : set_a) {
        for (int b : set_b) {
            result.push_back(a + b);
        }
    }

    std::sort(result.begin(), result.end());
    return result;
}

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class Sumset {
    public static int[] sumset(int[] setA, int[] setB) {
        List<Integer> values = new ArrayList<>();
        for (int a : setA) {
            for (int b : setB) {
                values.add(a + b);
            }
        }
        Collections.sort(values);
        int[] result = new int[values.size()];
        for (int i = 0; i < values.size(); i++) {
            result[i] = values.get(i);
        }
        return result;
    }
}

fun sumset(setA: IntArray, setB: IntArray): IntArray {
    val result = IntArray(setA.size * setB.size)
    var index = 0

    for (valueB in setB) {
        for (valueA in setA) {
            result[index++] = valueA + valueB
        }
    }

    result.sort()
    return result
}

